import React, { useState } from "react";
import Navbar from "../../components/Navbar";
import "../../App.css";

function AdminStockManagement() {
  const [stock, setStock] = useState([
    { name: "Milk", quantity: 20, expiry: "2026-01-10", price: 30 },
    { name: "Maggi", quantity: 40, expiry: "2026-03-01", price: 15 },
  ]);

  const [newItem, setNewItem] = useState({
    name: "",
    quantity: "",
    expiry: "",
    price: "",
  });

  const addItem = () => {
    if (!newItem.name || !newItem.quantity) return;

    setStock([
      ...stock,
      {
        name: newItem.name,
        quantity: Number(newItem.quantity),
        expiry: newItem.expiry,
        price: Number(newItem.price),
      },
    ]);

    setNewItem({ name: "", quantity: "", expiry: "", price: "" });
  };

  return (
    <>
      {/* Dashboard Navbar */}
      <Navbar variant="dashboard" />

      <div className="container">
        {/* Page Header */}
        <div className="card">
          <h2>Admin – Stock Management</h2>
          <p className="note">
            Full control over inventory, pricing and expiry
          </p>
        </div>

        {/* Add Product */}
        <div className="card">
          <h3>Add New Product</h3>

          <form>
            <input
              placeholder="Product name"
              value={newItem.name}
              onChange={(e) =>
                setNewItem({ ...newItem, name: e.target.value })
              }
            />

            <input
              type="number"
              placeholder="Quantity"
              value={newItem.quantity}
              onChange={(e) =>
                setNewItem({ ...newItem, quantity: e.target.value })
              }
            />

            <input
              type="date"
              value={newItem.expiry}
              onChange={(e) =>
                setNewItem({ ...newItem, expiry: e.target.value })
              }
            />

            <input
              type="number"
              placeholder="Price"
              value={newItem.price}
              onChange={(e) =>
                setNewItem({ ...newItem, price: e.target.value })
              }
            />

            <button type="button" onClick={addItem}>
              Add Item
            </button>
          </form>
        </div>

        {/* Stock Table */}
        <div className="card">
          <h3>Current Inventory</h3>

          {stock.length === 0 ? (
            <p className="note">No products added yet.</p>
          ) : (
            <table>
              <thead>
                <tr>
                  <th>Product</th>
                  <th>Quantity</th>
                  <th>Expiry</th>
                  <th>Price</th>
                </tr>
              </thead>
              <tbody>
                {stock.map((item, index) => (
                  <tr key={index}>
                    <td>{item.name}</td>
                    <td>{item.quantity}</td>
                    <td>{item.expiry}</td>
                    <td>₹{item.price}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>
    </>
  );
}

export default AdminStockManagement;
